import heapq
from collections import defaultdict

def solve(n: int, edges: list[list[int]]) -> int:
    # Build the graph: original edges and reversed edges (for possible flipping)
    graph = defaultdict(list)
    reversed_edges = defaultdict(list)  # To store edges that can be flipped (v -> u)

    for u, v, w in edges:
        graph[u].append((v, w, False))  # (neighbor, weight, is_flipped)
        reversed_edges[v].append((u, w))  # (original source, weight)

    # Priority queue: (total_cost, current_node, has_used_flip)
    heap = []
    heapq.heappush(heap, (0, 0, False))

    # Visited: (node, has_used_flip) -> min_cost
    visited = {}
    visited[(0, False)] = 0

    while heap:
        current_cost, u, used_flip = heapq.heappop(heap)
        if u == n - 1:
            return current_cost

        if current_cost > visited.get((u, used_flip), float('inf')):
            continue

        # Explore original edges
        for v, w, is_flipped in graph[u]:
            new_cost = current_cost + w
            if (v, used_flip) not in visited or new_cost < visited[(v, used_flip)]:
                visited[(v, used_flip)] = new_cost
                heapq.heappush(heap, (new_cost, v, used_flip))

        # Explore flipping an incoming edge if not used flip yet
        if not used_flip:
            for v, w in reversed_edges[u]:
                new_cost = current_cost + 2 * w
                if (v, True) not in visited or new_cost < visited[(v, True)]:
                    visited[(v, True)] = new_cost
                    heapq.heappush(heap, (new_cost, v, True))

    # Check if we can reach the target with or without flipping
    res = float('inf')
    for flip in [False, True]:
        if (n - 1, flip) in visited:
            res = min(res, visited[(n - 1, flip)])

    return res if res != float('inf') else -1
